{
  "name": "PsychStim Batch Generator",
  "description": "An automated workflow for generating psychological stimuli using Gemini. Upload multiple images and apply consistent or individual prompts to create stimulus variations at scale."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type TaskStatus = 'pending' | 'processing' | 'completed' | 'error';

export interface StimulusTask {
  id: string;
  sourceFile: File;
  sourcePreview: string;
  prompt: string;
  resultUrl?: string;
  status: TaskStatus;
  error?: string;
  startTime?: number;
  endTime?: number;
}

export interface BatchStats {
  total: number;
  completed: number;
  processing: number;
  error: number;
}

import { GoogleGenAI } from "@google/genai";

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64String = reader.result as string;
      // Remove the data:image/xxx;base64, prefix
      resolve(base64String.split(',')[1]);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const generateStimulus = async (
  sourceFile: File,
  prompt: string
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const base64Data = await fileToBase64(sourceFile);

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Data,
            mimeType: sourceFile.type,
          },
        },
        {
          text: prompt,
        },
      ],
    },
  });

  if (!response.candidates?.[0]?.content?.parts) {
    throw new Error("Invalid response from Gemini: No parts found.");
  }

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data found in Gemini response.");
};

import React from 'react';
