  task: StimulusTask;
  onRemove: (id: string) => void;
  onUpdatePrompt: (id: string, prompt: string) => void;
}

export const StimulusCard: React.FC<StimulusCardProps> = ({ task, onRemove, onUpdatePrompt }) => {
