import React, { useState, useCallback, useMemo } from 'react';
import { StimulusTask, TaskStatus } from './types';
import { StimulusCard } from './components/StimulusCard';
import { generateStimulus } from './services/geminiService';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<StimulusTask[]>([]);
  const [globalPrompt, setGlobalPrompt] = useState('Subtly increase the emotional intensity of the expression, making the subject appear 20% more fearful while keeping all other features consistent.');
  const [isProcessing, setIsProcessing] = useState(false);

  const stats = useMemo(() => ({
    total: tasks.length,
    completed: tasks.filter(t => t.status === 'completed').length,
    processing: tasks.filter(t => t.status === 'processing').length,
    error: tasks.filter(t => t.status === 'error').length,
    pending: tasks.filter(t => t.status === 'pending').length,
  }), [tasks]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;

    const newFiles = Array.from(e.target.files);
    const newTasks: StimulusTask[] = newFiles.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      sourceFile: file,
      sourcePreview: URL.createObjectURL(file),
      prompt: globalPrompt,
      status: 'pending' as TaskStatus,
    }));

    setTasks(prev => [...prev, ...newTasks]);
    // Reset input
    e.target.value = '';
  };

  const updateTaskPrompt = (id: string, prompt: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, prompt } : t));
  };

  const removeTask = (id: string) => {
    setTasks(prev => {
      const task = prev.find(t => t.id === id);
      if (task) URL.revokeObjectURL(task.sourcePreview);
      return prev.filter(t => t.id !== id);
    });
  };

  const applyGlobalPrompt = () => {
    setTasks(prev => prev.map(t => 
      t.status === 'pending' ? { ...t, prompt: globalPrompt } : t
    ));
  };

  const runBatch = async () => {
    if (isProcessing) return;
    setIsProcessing(true);

    const pendingTasks = tasks.filter(t => t.status === 'pending' || t.status === 'error');

    // Process sequentially to respect rate limits and handle errors better
    for (const task of pendingTasks) {
      setTasks(prev => prev.map(t => t.id === task.id ? { ...t, status: 'processing', error: undefined } : t));

      try {
        const resultUrl = await generateStimulus(task.sourceFile, task.prompt);
        setTasks(prev => prev.map(t => t.id === task.id ? { 
          ...t, 
          status: 'completed', 
          resultUrl,
          endTime: Date.now() 
        } : t));
      } catch (err: any) {
        setTasks(prev => prev.map(t => t.id === task.id ? { 
          ...t, 
          status: 'error', 
          error: err.message || 'Unknown error occurred' 
        } : t));
      }
    }

    setIsProcessing(false);
  };

  const clearCompleted = () => {
    setTasks(prev => prev.filter(t => t.status !== 'completed'));
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header */}
      <header className="mb-10 text-center">
        <div className="flex items-center justify-center gap-2 mb-2">
          <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-200">
            <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
            </svg>
          </div>
          <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight">PsychStim <span className="text-blue-600">Batch</span></h1>
        </div>
        <p className="text-gray-500 max-w-2xl mx-auto">
          Automate the creation of psychological stimulus sets. Upload your baseline images, define transformation rules, and let Gemini generate consistent variations in bulk.
        </p>
      </header>

      {/* Control Panel */}
      <section className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-12">
        {/* Global Prompt Settings */}
        <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-gray-200 p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-bold flex items-center gap-2">
              <svg className="w-5 h-5 text-blue-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
              Batch Transformation Rules
            </h2>
            <button 
              onClick={applyGlobalPrompt}
              className="text-xs font-semibold text-blue-600 hover:text-blue-800 uppercase tracking-wider"
            >
              Apply to All Pending
            </button>
          </div>
          <textarea
            value={globalPrompt}
            onChange={(e) => setGlobalPrompt(e.target.value)}
            className="w-full h-32 p-4 bg-gray-50 border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all resize-none text-gray-700"
            placeholder="e.g. Modify the facial expression to be slightly more aggressive..."
          />
          <p className="text-[11px] text-gray-400 mt-2">
            Tip: Be specific about intensity (e.g. "20% more") and what to preserve (e.g. "keep lighting and background consistent").
          </p>
        </div>

        {/* Action Panel */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-6 flex flex-col justify-between">
          <div>
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              <svg className="w-5 h-5 text-green-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
              </svg>
              Input
            </h2>
            <label className="block w-full cursor-pointer">
              <span className="sr-only">Choose files</span>
              <div className="flex flex-col items-center justify-center border-2 border-dashed border-gray-200 rounded-xl py-8 hover:border-blue-400 hover:bg-blue-50 transition-all group">
                <svg className="w-8 h-8 text-gray-400 group-hover:text-blue-500 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                <span className="text-sm font-medium text-gray-600">Click to Upload Baseline Images</span>
