          </div>

          <div className="mt-6 flex flex-col gap-3">
             <button
              onClick={runBatch}
              disabled={isProcessing || stats.pending + stats.error === 0}
              className={`w-full py-4 rounded-xl font-bold text-white transition-all transform active:scale-95 flex items-center justify-center gap-2 ${
                isProcessing || stats.pending + stats.error === 0 
                ? 'bg-gray-300 cursor-not-allowed' 
                : 'bg-blue-600 hover:bg-blue-700 shadow-lg shadow-blue-200'
              }`}
            >
              {isProcessing ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Processing Batch...
                </>
              ) : (
                <>
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                  Start Batch Generation ({stats.pending + stats.error})
                </>
              )}
            </button>
            <button 
              onClick={clearCompleted}
              className="w-full py-2 text-sm text-gray-500 hover:text-gray-700 font-medium"
            >
              Clear Completed Tasks
            </button>
          </div>
        </div>
      </section>

      {/* Progress & Stats */}
      {tasks.length > 0 && (
        <div className="mb-8">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-xl font-bold text-gray-900">Queue & Results</h2>
            <div className="flex gap-4">
              <div className="flex flex-col items-end">
                <span className="text-[10px] uppercase font-bold text-gray-400">Progress</span>
                <span className="text-lg font-bold text-blue-600">{Math.round((stats.completed / stats.total) * 100)}%</span>
              </div>
              <div className="flex flex-col items-end">
                <span className="text-[10px] uppercase font-bold text-gray-400">Items</span>
                <span className="text-lg font-bold text-gray-900">{stats.completed} / {stats.total}</span>
              </div>
            </div>
          </div>

          <div className="w-full bg-gray-200 rounded-full h-2.5 mb-8">
            <div 
              className="bg-blue-600 h-2.5 rounded-full transition-all duration-500" 
              style={{ width: `${(stats.completed / stats.total) * 100}%` }}
            ></div>
          </div>

          {/* Task Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {tasks.map(task => (
              <StimulusCard 
                key={task.id} 
                task={task} 
                onRemove={removeTask}
                onUpdatePrompt={updateTaskPrompt}
              />
            ))}
          </div>
        </div>
      )}

      {/* Empty State */}
      {tasks.length === 0 && (
        <div className="flex flex-col items-center justify-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
           <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-6">
             <svg className="w-10 h-10 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
             </svg>
           </div>
           <h3 className="text-xl font-bold text-gray-900 mb-2">No Stimuli to Generate</h3>
           <p className="text-gray-500">Upload your images to get started with the batch process.</p>
        </div>
      )}

      {/* Footer Info */}
      <footer className="mt-20 pt-8 border-t border-gray-100 flex flex-col md:flex-row justify-between items-center text-gray-400 text-xs">
        <p>© 2024 Psychological Research Tools powered by Gemini</p>
        <div className="flex gap-6 mt-4 md:mt-0">
          <span>Model: gemini-2.5-flash-image</span>
          <span>Batch Optimization Enabled</span>
        </div>
      </footer>
    </div>
  );
};

