import { GoogleGenAI } from "@google/genai";

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64String = reader.result as string;
      resolve(base64String.split(',')[1]);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const urlToBase64 = async (url: string): Promise<string> => {
  const response = await fetch(url);
  const blob = await response.blob();
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(blob);
    reader.onload = () => {
      const base64String = reader.result as string;
      resolve(base64String.split(',')[1]);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const generateStimulus = async (
  sourceFile: File,
  prompt: string,
  referenceImageUrl?: string | null
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const sourceBase64 = await fileToBase64(sourceFile);

  const parts: any[] = [
    {
      inlineData: {
        data: sourceBase64,
        mimeType: sourceFile.type,
      },
    },
    { text: prompt }
  ];

  // If a reference image is provided (Result A), add it to the prompt parts
  // to help the model maintain environment consistency.
  if (referenceImageUrl) {
    const refBase64 = await urlToBase64(referenceImageUrl);
    parts.unshift({
      inlineData: {
        data: refBase64,
        mimeType: 'image/png',
      },
    });
    parts.push({ text: "Use the environment/lighting from the first image provided as the reference for this new generation." });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
  });

  if (!response.candidates?.[0]?.content?.parts) {
    throw new Error("Invalid response from Gemini: No parts found.");
  }

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data found in Gemini response.");
};

