import React, { useState, useMemo } from 'react';
import { StimulusPair, TaskStatus } from './types';
import { PairCard } from './components/PairCard';
import { generateStimulus } from './services/geminiService';

const DEFAULT_PROMPT_A = `Use the object from the image I provide below.

Generate a photorealistic scene where this exact same object is placed in a simple, realistic environment that is naturally appropriate for this kind of object.

HARD CONSTRAINTS:
– The object must remain identical (same shape, geometry, colours, materials).
– Keep the object centred and occupying 25–35% of the frame.
– Use neutral, natural lighting (not dramatic, not stylised).
– Keep the environment minimal: include only large, low-salience context elements that make sense for this object (e.g., ground, floor, grass, wall, simple surface, neutral background forms).
– You may include 1–2 low-salience background elements, but they must be generic and non-diagnostic.

Do NOT add text, logos, people, faces, screens, or reflections.
– Do NOT add clutter, patterns, or decorations.

IMPORTANT:
The model must infer an appropriate setting for the object, but keep it simple, generic, and non-distinctive.`;

const DEFAULT_PROMPT_B = `Use this new second object this is structurally different from the first object I gave you, please acknowledge this. Now place this new (_) in a similar type of environment used in the reference Image A.

KEEP THE SAME:
– Exact object identity (same model, same proportions, same materials)
– Object size in the frame
– Object pose/orientation
– Lighting style (neutral, natural)
– Overall simplicity and minimalism

ONLY CHANGE:
– The specific background instance (e.g., different ground texture, different neutral foliage, different simple surface)
– The 1–2 background elements (swap tree for different tree, rock for different rock, wall for different wall, etc.)
– Minor colour/texture variation within natural limits

DO NOT CHANGE:
– Lighting type
– Camera angle / framing
– Semantic meaning of the scene
– Object identity`;

const App: React.FC = () => {
  const [pairs, setPairs] = useState<StimulusPair[]>([]);
  const [promptA, setPromptA] = useState(DEFAULT_PROMPT_A);
  const [promptB, setPromptB] = useState(DEFAULT_PROMPT_B);
  const [isProcessing, setIsProcessing] = useState(false);

  const stats = useMemo(() => {
    const total = pairs.length;
    const completed = pairs.filter(p => p.itemA.status === 'completed' && p.itemB.status === 'completed').length;
    return { total, completed };
  }, [pairs]);

  const addNewPair = () => {
    const newPair: StimulusPair = {
      id: Math.random().toString(36).substring(2, 11).toUpperCase(),
      objectName: '',
      itemA: { id: 'a', sourceFile: null, sourcePreview: null, resultUrl: null, status: 'pending' },
      itemB: { id: 'b', sourceFile: null, sourcePreview: null, resultUrl: null, status: 'pending' },
      promptA: promptA,
      promptB: promptB,
    };
    setPairs(prev => [...prev, newPair]);
  };

  const updateObjectName = (pairId: string, objectName: string) => {
    setPairs(prev => prev.map(p => p.id === pairId ? { ...p, objectName } : p));
  };

  const handleUpload = (pairId: string, type: 'A' | 'B', file: File) => {
    setPairs(prev => prev.map(p => {
      if (p.id === pairId) {
        const item = type === 'A' ? p.itemA : p.itemB;
        if (item.sourcePreview) URL.revokeObjectURL(item.sourcePreview);
        const newItem = {
          ...item,
          sourceFile: file,
          sourcePreview: URL.createObjectURL(file),
          status: 'pending' as TaskStatus,
          error: undefined
        };
        return type === 'A' ? { ...p, itemA: newItem } : { ...p, itemB: newItem };
      }
      return p;
    }));
  };

  const removePair = (pairId: string) => {
    setPairs(prev => {
      const p = prev.find(pair => pair.id === pairId);
      if (p) {
        if (p.itemA.sourcePreview) URL.revokeObjectURL(p.itemA.sourcePreview);
        if (p.itemB.sourcePreview) URL.revokeObjectURL(p.itemB.sourcePreview);
      }
      return prev.filter(pair => pair.id !== pairId);
    });
  };

  const runAllPairs = async () => {
    if (isProcessing) return;
    setIsProcessing(true);

    const pairsToProcess = [...pairs].filter(p => 
      (p.itemA.status !== 'completed' || p.itemB.status !== 'completed') && 
      p.itemA.sourceFile && p.itemB.sourceFile
    );

    for (const pair of pairsToProcess) {
      // Step 1: Generate Stimulus A
      if (pair.itemA.status !== 'completed') {
        setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemA: { ...p.itemA, status: 'processing', error: undefined } } : p));
        try {
          const resultA = await generateStimulus(pair.itemA.sourceFile!, pair.promptA);
          setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemA: { ...p.itemA, status: 'completed', resultUrl: resultA } } : p));
          // Update local reference
          pair.itemA.resultUrl = resultA;
          pair.itemA.status = 'completed';
        } catch (err: any) {
          setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemA: { ...p.itemA, status: 'error', error: err.message } } : p));
          continue; 
        }
      }

      // Step 2: Generate Stimulus B using Result A as reference
      if (pair.itemB.status !== 'completed' && pair.itemA.resultUrl) {
        setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemB: { ...p.itemB, status: 'processing', error: undefined } } : p));
        try {
          // Dynamic prompt B processing: replace (_) or __ with objectName
          const objectDisplay = pair.objectName.trim() || 'object';
          const processedPromptB = pair.promptB
            .replace(/\(\_\)/g, objectDisplay)
            .replace(/\_\_/g, objectDisplay);

          const resultB = await generateStimulus(pair.itemB.sourceFile!, processedPromptB, pair.itemA.resultUrl);
          setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemB: { ...p.itemB, status: 'completed', resultUrl: resultB } } : p));
        } catch (err: any) {
          setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemB: { ...p.itemB, status: 'error', error: err.message } } : p));
        }
      }
    }

    setIsProcessing(false);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-10">
      <header className="mb-12 text-center">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight mb-3">
          Psych<span className="text-blue-600">Stim</span> Pairs
        </h1>
        <p className="text-gray-500 max-w-xl mx-auto text-sm leading-relaxed">
          Automated sequential workflow for research stimuli. 
          Generates Target (A), then replicates its environment for Variant (B).
        </p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Sidebar Controls */}
        <aside className="lg:col-span-1 space-y-6">
          <div className="bg-white rounded-2xl p-6 border border-gray-200 shadow-sm">
            <h2 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4">Master Rules</h2>

            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-bold text-blue-600 uppercase mb-1 block">Prompt A (Baseline)</label>
                <textarea 
                  value={promptA} 
                  onChange={(e) => setPromptA(e.target.value)}
                  className="w-full h-32 text-[10px] p-3 bg-gray-50 border-gray-100 rounded-xl resize-none focus:ring-1 focus:ring-blue-500 transition-all font-mono"
                />
              </div>

              <div>
                <label className="text-[10px] font-bold text-purple-600 uppercase mb-1 block">Prompt B (Variant)</label>
                <textarea 
                  value={promptB} 
                  onChange={(e) => setPromptB(e.target.value)}
                  className="w-full h-32 text-[10px] p-3 bg-gray-50 border-gray-100 rounded-xl resize-none focus:ring-1 focus:ring-purple-500 transition-all font-mono"
                />
                <p className="text-[9px] text-gray-400 mt-1 italic">Use (_) or __ for object name injection.</p>
              </div>
            </div>
          </div>

          <div className="bg-blue-600 rounded-2xl p-6 text-white shadow-xl shadow-blue-100">
             <div className="flex items-center justify-between mb-6">
                <span className="text-[10px] font-bold uppercase tracking-widest opacity-80">Batch Progress</span>
                <span className="text-xl font-black">{stats.completed}/{stats.total}</span>
             </div>
             <button 
               onClick={runAllPairs}
               disabled={isProcessing || stats.total === 0}
               className={`w-full py-4 rounded-xl font-bold transition-all transform active:scale-95 flex items-center justify-center gap-2 ${
                 isProcessing || stats.total === 0 ? 'bg-white/20 cursor-not-allowed' : 'bg-white text-blue-600 hover:shadow-lg'
               }`}
             >
               {isProcessing ? (
                 <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
               ) : 'Run Sequential Batch'}
             </button>
          </div>
        </aside>

        {/* Main Grid */}
        <main className="lg:col-span-3">
          <div className="flex items-center justify-between mb-6">
             <h2 className="text-lg font-bold text-gray-800">Experiment Queue</h2>
             <button 
               onClick={addNewPair}
               className="px-4 py-2 bg-gray-900 text-white text-xs font-bold rounded-full hover:bg-gray-800 transition-all flex items-center gap-2"
             >
               <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
               </svg>
               Add New Trial
             </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {pairs.map((pair, idx) => (
              <PairCard 
                key={pair.id} 
                pair={pair} 
                index={idx}
                onRemove={removePair} 
                onUpload={handleUpload}
                onUpdateObjectName={updateObjectName}
              />
            ))}
          </div>

          {pairs.length === 0 && (
            <div className="py-24 flex flex-col items-center justify-center border-2 border-dashed border-gray-100 rounded-3xl bg-gray-50/50">
               <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center shadow-sm mb-4">
                 <svg className="w-8 h-8 text-gray-200" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                 </svg>
               </div>
               <p className="text-sm font-medium text-gray-400">Add a trial pair to begin</p>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

