export const PairCard: React.FC<PairCardProps> = ({ pair, index, onRemove, onUpload, onUpdateObjectName, onRefresh }) => {
  const [showPromptPreview, setShowPromptPreview] = useState(false);
  const isLocked = pair.itemA.status === 'processing' || pair.itemB.status === 'processing';
  const pairIndexStr = String(index).padStart(2, '0');

  const downloadNameA = `obj${pairIndexStr}_T_scene.png`;
  const downloadNameB = `obj${pairIndexStr}_F_scene.png`;

  const objectDisplay = pair.objectName.trim() || '(__)';
  const processedPromptBPreview = pair.promptB
    .replace(/\(\_\)/g, `[${objectDisplay}]`)
    .replace(/\_\_/g, `[${objectDisplay}]`);

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-5 flex flex-col gap-4 transition-all hover:shadow-md">
      <div className="flex items-center justify-between pb-3 border-b border-gray-50">
        <div className="flex items-center gap-3 flex-1 mr-4">
           <div className="w-6 h-6 rounded bg-gray-900 flex items-center justify-center text-[10px] font-bold text-white shrink-0">
             {pairIndexStr}
           </div>
           <div className="flex-1">
             <div className="relative">
                <input
                  type="text"
                  value={pair.objectName}
                  onChange={(e) => onUpdateObjectName(pair.id, e.target.value)}
                  placeholder="Input Object Name (e.g. phone)"
                  className="w-full bg-gray-100 border-2 border-transparent focus:border-blue-500 focus:bg-white rounded-lg px-3 py-1.5 text-xs font-bold transition-all outline-none"
                  disabled={isLocked}
                />
                <div className="absolute right-2 top-1/2 -translate-y-1/2 text-[9px] font-bold text-gray-400 uppercase pointer-events-none">
                  Identity
                </div>
             </div>
           </div>
        </div>
        <div className="flex items-center gap-1.5">
          <button 
            onClick={() => onRefresh(pair.id)}
            disabled={isLocked || !pair.itemA.sourceFile || !pair.itemB.sourceFile}
            className={`p-1.5 rounded-lg transition-all ${isLocked ? 'text-gray-200' : 'text-gray-400 hover:text-blue-600 hover:bg-blue-50'}`}
            title="Refresh Stimulus (Regenerate)"
          >
            <svg className={`w-4 h-4 ${isLocked ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </button>
          <button 
            onClick={() => setShowPromptPreview(!showPromptPreview)}
            className={`p-1.5 rounded-lg transition-colors ${showPromptPreview ? 'bg-blue-50 text-blue-600' : 'text-gray-400 hover:bg-gray-50'}`}
            title="View Prompt B Injection"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
          </button>
          <button 
            onClick={() => onRemove(pair.id)}
            disabled={isLocked}
            className="p-1.5 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
            </svg>
          </button>
        </div>
      </div>

      {showPromptPreview && (
        <div className="bg-blue-50/50 rounded-xl p-3 border border-blue-100 text-[10px] leading-relaxed animate-in fade-in slide-in-from-top-2 duration-200">
           <div className="flex items-center justify-between mb-1">
             <span className="font-bold text-blue-600 uppercase">Prompt B Preview (Injected)</span>
             <span className="text-gray-400">Replacing (_) with {objectDisplay}</span>
           </div>
           <p className="text-gray-600 italic whitespace-pre-wrap font-mono">
             {processedPromptBPreview}
           </p>
        </div>
      )}

      <div className="flex gap-4">
        <ItemSlot 
          item={pair.itemA} 
          label="Object A (Target)" 
          onFileSelect={(f) => onUpload(pair.id, 'A', f)}
          isLocked={isLocked}
          downloadName={downloadNameA}
        />
        <div className="flex items-center text-gray-200">
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" />
          </svg>
        </div>
        <ItemSlot 
          item={pair.itemB} 
          label="Object B (Variant)" 
          onFileSelect={(f) => onUpload(pair.id, 'B', f)}
          isLocked={isLocked}
          downloadName={downloadNameB}
        />
      </div>
    </div>
  );
};

import React, { useState, useMemo, useCallback } from 'react';
import { StimulusPair, TaskStatus } from './types';
import { PairCard } from './components/PairCard';
import { generateStimulus } from './services/geminiService';

const DEFAULT_PROMPT_A = `Use the object from the image I provide below.

Generate a photorealistic scene where this exact same object is placed in a simple, realistic environment that is naturally appropriate for this kind of object.

HARD CONSTRAINTS:
– The object must remain identical (same shape, geometry, colours, materials).
– Keep the object centred and occupying 25–35% of the frame.
– Use neutral, natural lighting (not dramatic, not stylised).
– Keep the environment minimal: include only large, low-salience context elements that make sense for this object (e.g., ground, floor, grass, wall, simple surface, neutral background forms).
– You may include 1–2 low-salience background elements, but they must be generic and non-diagnostic.

Do NOT add text, logos, people, faces, screens, or reflections.
– Do NOT add clutter, patterns, or decorations.

IMPORTANT:
The model must infer an appropriate setting for the object, but keep it simple, generic, and non-distinctive.`;

const DEFAULT_PROMPT_B = `Use this new second object this is structurally different from the first object I gave you, please acknowledge this. Now place this new (_) in a similar type of environment used in the reference Image A.

KEEP THE SAME:
– Exact object identity (same model, same proportions, same materials)
– Object size in the frame
– Object pose/orientation
– Lighting style (neutral, natural)
– Overall simplicity and minimalism

ONLY CHANGE:
– The specific background instance (e.g., different ground texture, different neutral foliage, different simple surface)
– The 1–2 background elements (swap tree for different tree, rock for different rock, wall for different wall, etc.)
– Minor colour/texture variation within natural limits

DO NOT CHANGE:
– Lighting type
– Camera angle / framing
– Semantic meaning of the scene
– Object identity`;

const App: React.FC = () => {
  const [pairs, setPairs] = useState<StimulusPair[]>([]);
  const [promptA, setPromptA] = useState(DEFAULT_PROMPT_A);
  const [promptB, setPromptB] = useState(DEFAULT_PROMPT_B);
  const [isProcessing, setIsProcessing] = useState(false);

  const stats = useMemo(() => {
    const total = pairs.length;
    const completed = pairs.filter(p => p.itemA.status === 'completed' && p.itemB.status === 'completed').length;
    return { total, completed };
  }, [pairs]);

  const addNewPair = () => {
    const newPair: StimulusPair = {
      id: Math.random().toString(36).substring(2, 11).toUpperCase(),
      objectName: '',
      itemA: { id: 'a', sourceFile: null, sourcePreview: null, resultUrl: null, status: 'pending' },
      itemB: { id: 'b', sourceFile: null, sourcePreview: null, resultUrl: null, status: 'pending' },
      promptA: promptA,
      promptB: promptB,
    };
    setPairs(prev => [...prev, newPair]);
  };

  const updateObjectName = (pairId: string, objectName: string) => {
    setPairs(prev => prev.map(p => p.id === pairId ? { ...p, objectName } : p));
  };

  const handleUpload = (pairId: string, type: 'A' | 'B', file: File) => {
    setPairs(prev => prev.map(p => {
      if (p.id === pairId) {
        const item = type === 'A' ? p.itemA : p.itemB;
        if (item.sourcePreview) URL.revokeObjectURL(item.sourcePreview);
        const newItem = {
          ...item,
          sourceFile: file,
          sourcePreview: URL.createObjectURL(file),
          status: 'pending' as TaskStatus,
          error: undefined
        };
        return type === 'A' ? { ...p, itemA: newItem } : { ...p, itemB: newItem };
      }
      return p;
    }));
  };

  const removePair = (pairId: string) => {
    setPairs(prev => {
      const p = prev.find(pair => pair.id === pairId);
      if (p) {
        if (p.itemA.sourcePreview) URL.revokeObjectURL(p.itemA.sourcePreview);
        if (p.itemB.sourcePreview) URL.revokeObjectURL(p.itemB.sourcePreview);
      }
      return prev.filter(pair => pair.id !== pairId);
    });
  };

  // Logic to process a single pair sequentially
  const processPair = async (pair: StimulusPair) => {
    // Step 1: Generate Stimulus A
    setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemA: { ...p.itemA, status: 'processing', error: undefined } } : p));
    let currentResultA = pair.itemA.resultUrl;

    try {
      currentResultA = await generateStimulus(pair.itemA.sourceFile!, promptA);
      setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemA: { ...p.itemA, status: 'completed', resultUrl: currentResultA } } : p));
    } catch (err: any) {
      setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemA: { ...p.itemA, status: 'error', error: err.message } } : p));
      return; // Skip B if A fails
    }

    // Step 2: Generate Stimulus B using Result A as reference
    setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemB: { ...p.itemB, status: 'processing', error: undefined } } : p));
    try {
      const objectDisplay = pair.objectName.trim() || 'object';
      const processedPromptB = promptB
        .replace(/\(\_\)/g, objectDisplay)
        .replace(/\_\_/g, objectDisplay);

      const resultB = await generateStimulus(pair.itemB.sourceFile!, processedPromptB, currentResultA);
      setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemB: { ...p.itemB, status: 'completed', resultUrl: resultB } } : p));
    } catch (err: any) {
      setPairs(prev => prev.map(p => p.id === pair.id ? { ...p, itemB: { ...p.itemB, status: 'error', error: err.message } } : p));
    }
  };

  const runAllPairs = async () => {
    if (isProcessing) return;
    setIsProcessing(true);

    const pairsToProcess = [...pairs].filter(p => 
      (p.itemA.status !== 'completed' || p.itemB.status !== 'completed') && 
      p.itemA.sourceFile && p.itemB.sourceFile
    );

    for (const pair of pairsToProcess) {
      await processPair(pair);
    }

    setIsProcessing(false);
  };

  const runSinglePair = async (pairId: string) => {
    const pair = pairs.find(p => p.id === pairId);
    if (!pair || !pair.itemA.sourceFile || !pair.itemB.sourceFile) return;

    // If global processing is happening, we might want to prevent this or just await
    // For simplicity, we'll allow single refresh if global isn't running
    if (isProcessing) return;

    setIsProcessing(true);
    await processPair(pair);
    setIsProcessing(false);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-10">
      <header className="mb-12 text-center">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight mb-3">
          Psych<span className="text-blue-600">Stim</span> Pairs
        </h1>
        <p className="text-gray-500 max-w-xl mx-auto text-sm leading-relaxed">
          Batch generation for experimental stimulus sets. 
          Generates <span className="text-blue-600 font-bold">Target (A)</span>, then replicates environment for <span className="text-purple-600 font-bold">Variant (B)</span>.
        </p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Sidebar Controls */}
        <aside className="lg:col-span-1 space-y-6">
          <div className="bg-white rounded-2xl p-6 border border-gray-200 shadow-sm sticky top-10">
            <h2 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 flex items-center gap-2">
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37a1.724 1.724 0 002.572-1.065z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
              Master Templates
            </h2>

            <div className="space-y-5">
              <div>
                <label className="text-[10px] font-bold text-blue-600 uppercase mb-1 block">Prompt Template A</label>
                <textarea 
                  value={promptA} 
                  onChange={(e) => setPromptA(e.target.value)}
                  className="w-full h-32 text-[10px] p-3 bg-gray-50 border-gray-100 rounded-xl resize-none focus:ring-1 focus:ring-blue-500 transition-all font-mono leading-relaxed"
                />
              </div>

              <div>
                <label className="text-[10px] font-bold text-purple-600 uppercase mb-1 block">Prompt Template B</label>
                <textarea 
                  value={promptB} 
                  onChange={(e) => setPromptB(e.target.value)}
                  className="w-full h-32 text-[10px] p-3 bg-gray-50 border-gray-100 rounded-xl resize-none focus:ring-1 focus:ring-purple-500 transition-all font-mono leading-relaxed"
                />
                <div className="mt-2 p-2 bg-purple-50 rounded-lg border border-purple-100">
                  <p className="text-[9px] text-purple-700 font-medium">
                    <span className="font-bold">Placeholder:</span> Use <code className="bg-purple-200 px-1 rounded">(_)</code> in this text to inject the Object Name from each trial.
                  </p>
                </div>
              </div>
            </div>

            <div className="mt-8">
               <button 
                 onClick={runAllPairs}
                 disabled={isProcessing || stats.total === 0}
                 className={`w-full py-4 rounded-2xl font-black transition-all transform active:scale-95 flex flex-col items-center justify-center gap-1 shadow-xl ${
                   isProcessing || stats.total === 0 
                   ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                   : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200'
                 }`}
               >
                 {isProcessing ? (
                   <>
                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                    <span className="text-[10px] uppercase">Processing...</span>
                   </>
                 ) : (
                   <>
                    <span className="text-lg uppercase tracking-tight">Generate Batch</span>
                    <span className="text-[9px] font-bold uppercase opacity-70 tracking-widest">{stats.completed} / {stats.total} Trials Ready</span>
                   </>
                 )}
               </button>
            </div>
          </div>
        </aside>

        {/* Main Grid */}
        <main className="lg:col-span-3">
          <div className="flex items-center justify-between mb-8">
             <div>
                <h2 className="text-xl font-bold text-gray-800">Experiment Trials</h2>
                <p className="text-xs text-gray-400">Items named objXX_T and objXX_F | Individual refresh available</p>
             </div>
             <button 
               onClick={addNewPair}
               className="px-6 py-2.5 bg-gray-900 text-white text-xs font-black rounded-full hover:bg-gray-800 transition-all flex items-center gap-2 shadow-lg shadow-gray-200"
             >
               <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
               </svg>
               Add New Trial
             </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {pairs.map((pair, idx) => (
              <PairCard 
                key={pair.id} 
                pair={pair} 
                index={idx}
                onRemove={removePair} 
                onUpload={handleUpload}
                onUpdateObjectName={updateObjectName}
                onRefresh={runSinglePair}
              />
            ))}
          </div>

          {pairs.length === 0 && (
            <div className="py-32 flex flex-col items-center justify-center border-2 border-dashed border-gray-100 rounded-[3rem] bg-gray-50/50">
               <div className="w-20 h-20 bg-white rounded-3xl flex items-center justify-center shadow-sm mb-6">
                 <svg className="w-10 h-10 text-gray-200" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                 </svg>
               </div>
               <h3 className="text-lg font-bold text-gray-400">Queue Empty</h3>
               <p className="text-sm text-gray-300">Start by adding a new stimulus trial</p>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

export type TaskStatus = 'pending' | 'processing' | 'completed' | 'error';

export interface StimulusItem {
  id: string;
  sourceFile: File | null;
  sourcePreview: string | null;
  resultUrl: string | null;
  status: TaskStatus;
  error?: string;
}

export interface StimulusTask extends StimulusItem {
  prompt: string;
}

export interface StimulusPair {
  id: string;
  objectName: string;
  customNumber?: string; // Manual override for the objXX prefix
  itemA: StimulusItem;
  itemB: StimulusItem;
  promptA: string;
  promptB: string;
}

export interface BatchStats {
  totalPairs: number;
  completedPairs: number;
  processing: boolean;
}

import React, { useState } from 'react';
import { StimulusPair, StimulusItem } from '../types';

interface PairCardProps {
  pair: StimulusPair;
  index: number;
  onRemove: (id: string) => void;
  onUpload: (id: string, type: 'A' | 'B', file: File) => void;
  onUpdateObjectName: (id: string, name: string) => void;
  onUpdateObjectNumber: (id: string, num: string) => void;
  onRefresh: (id: string) => void;
}

const ItemSlot: React.FC<{ 
  item: StimulusItem; 
  label: string; 
  onFileSelect: (file: File) => void;
  isLocked: boolean;
  downloadName: string;
}> = ({ item, label, onFileSelect, isLocked, downloadName }) => {
  return (
    <div className="flex-1 flex flex-col gap-2">
      <div className="flex items-center justify-between">
        <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{label}</span>
        {item.status !== 'pending' && (
           <span className={`text-[9px] px-1.5 py-0.5 rounded font-bold uppercase ${
             item.status === 'processing' ? 'bg-blue-100 text-blue-600 animate-pulse' :
             item.status === 'completed' ? 'bg-green-100 text-green-600' :
             'bg-red-100 text-red-600'
           }`}>
             {item.status}
           </span>
        )}
      </div>

      <div className={`relative aspect-square rounded-xl border-2 border-dashed transition-all overflow-hidden flex items-center justify-center ${
        item.sourcePreview ? 'border-transparent' : 'border-gray-200 hover:border-blue-300 bg-gray-50'
      }`}>
        {item.sourcePreview ? (
          <div className="w-full h-full relative group">
            <img src={item.sourcePreview} className="w-full h-full object-cover" alt="Source" />
            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
               <span className="text-[10px] text-white font-bold">SOURCE</span>
            </div>
          </div>
        ) : (
          <label className={`w-full h-full flex flex-col items-center justify-center cursor-pointer ${isLocked ? 'pointer-events-none opacity-50' : ''}`}>
            <svg className="w-6 h-6 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            <input 
              type="file" 
              className="hidden" 
              accept="image/*"
              onChange={(e) => e.target.files?.[0] && onFileSelect(e.target.files[0])}
            />
          </label>
        )}
      </div>

      <div className={`mt-2 aspect-square rounded-xl border flex items-center justify-center overflow-hidden bg-gray-100 ${
        item.status === 'completed' ? 'border-green-200' : 'border-gray-100'
      }`}>
        {item.resultUrl ? (
          <div className="w-full h-full relative group">
            <img src={item.resultUrl} className="w-full h-full object-cover" alt="Result" />
            <a 
              href={item.resultUrl} 
              download={downloadName}
              className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-center p-2"
            >
              <div className="flex flex-col items-center">
                <span className="text-[10px] text-white font-bold mb-1">DOWNLOAD</span>
                <span className="text-[8px] text-white/70 font-mono break-all">{downloadName}</span>
              </div>
            </a>
          </div>
        ) : (
          <div className="text-center p-4">
             {item.status === 'processing' ? (
                <div className="space-y-2">
                  <div className="w-4 h-4 border-2 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
                  <span className="text-[10px] text-gray-400 font-medium uppercase">Generating...</span>
                </div>
             ) : (
                <span className="text-[10px] text-gray-300 font-medium uppercase text-center flex flex-col gap-1">
                  <span>Waiting for</span>
                  <span>Baseline A</span>
                </span>
             )}
          </div>
        )}
      </div>
      {item.error && <p className="text-[10px] text-red-500 mt-1 italic leading-tight">{item.error}</p>}
    </div>
  );
};

export const PairCard: React.FC<PairCardProps> = ({ pair, index, onRemove, onUpload, onUpdateObjectName, onUpdateObjectNumber, onRefresh }) => {
  const [showPromptPreview, setShowPromptPreview] = useState(false);
  const isLocked = pair.itemA.status === 'processing' || pair.itemB.status === 'processing';

  // Use custom number if provided, otherwise default to padded index
  const pairIndexStr = String(index).padStart(2, '0');
  const displayNum = pair.customNumber ?? pairIndexStr;

  // File naming uses the display number
  const downloadNameA = `obj${displayNum}_T_scene.png`;
  const downloadNameB = `obj${displayNum}_F_scene.png`;

  const objectDisplay = pair.objectName.trim() || '(__)';
  const processedPromptBPreview = pair.promptB
    .replace(/\(\_\)/g, `[${objectDisplay}]`)
    .replace(/\_\_/g, `[${objectDisplay}]`);

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-5 flex flex-col gap-4 transition-all hover:shadow-md">
      <div className="flex items-center justify-between pb-3 border-b border-gray-50">
        <div className="flex items-center gap-3 flex-1 mr-4">
           {/* Editable Object Number Badge */}
           <div className="relative group/num">
              <input
                type="text"
                value={displayNum}
                onChange={(e) => onUpdateObjectNumber(pair.id, e.target.value)}
                className="w-8 h-8 rounded bg-gray-900 text-center text-[10px] font-bold text-white shrink-0 outline-none focus:ring-2 focus:ring-blue-500 transition-all hover:bg-gray-800"
                title="Edit Object Number"
                disabled={isLocked}
              />
              <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-gray-800 text-white text-[8px] px-1.5 py-0.5 rounded opacity-0 group-hover/num:opacity-100 transition-opacity pointer-events-none whitespace-nowrap">
                Object #
              </div>
           </div>

           <div className="flex-1">
             <div className="relative">
                <input
                  type="text"
                  value={pair.objectName}
                  onChange={(e) => onUpdateObjectName(pair.id, e.target.value)}
                  placeholder="Input Object Name (e.g. phone)"
                  className="w-full bg-gray-100 border-2 border-transparent focus:border-blue-500 focus:bg-white rounded-lg px-3 py-1.5 text-xs font-bold transition-all outline-none"
                  disabled={isLocked}
